// Twilio WhatsApp inbound webhook format. n8n may expose form fields at root or under body.
const input = $input.first().json;
const body = input.body || input;
const headers = input.headers || {};
const header = name => headers[name] || headers[name.toLowerCase()] || headers[name.toUpperCase()] || '';

async function hmacSha1Base64(secret, data) {
  if (typeof require === 'function') {
    try {
      return require('crypto').createHmac('sha1', secret).update(data).digest('base64');
    } catch (_) {}
  }
  if (globalThis.crypto?.subtle) {
    const key = await crypto.subtle.importKey('raw', new TextEncoder().encode(secret), { name: 'HMAC', hash: 'SHA-1' }, false, ['sign']);
    const signature = await crypto.subtle.sign('HMAC', key, new TextEncoder().encode(data));
    return btoa(String.fromCharCode(...new Uint8Array(signature)));
  }
  throw new Error('No HMAC implementation available for Twilio signature validation');
}

async function validateTwilioSignature(webhookPath) {
  if (String($env.TWILIO_VALIDATE_WEBHOOK_SIGNATURE || '').toLowerCase() !== 'true') return true;
  const signature = String(header('x-twilio-signature') || '').trim();
  const authToken = String($env.TWILIO_AUTH_TOKEN || '').trim();
  const baseUrl = String($env.WEBHOOK_URL || '').replace(/\/$/, '');
  if (!signature || !authToken || !baseUrl) return false;
  const url = baseUrl + '/webhook/' + webhookPath;
  const signedData = Object.keys(body)
    .filter(key => body[key] !== undefined && body[key] !== null && typeof body[key] !== 'object')
    .sort()
    .reduce((acc, key) => acc + key + String(body[key]), url);
  const expected = await hmacSha1Base64(authToken, signedData);
  if (expected.length !== signature.length) return false;
  let diff = 0;
  for (let i = 0; i < expected.length; i += 1) diff |= expected.charCodeAt(i) ^ signature.charCodeAt(i);
  return diff === 0;
}

if (!(await validateTwilioSignature('feedback-listener'))) {
  return [{ json: { _skip: true, reason: 'Invalid Twilio webhook signature' } }];
}

const fromRaw = String(body.From || body.from || '').trim();
const toRaw = String(body.To || body.to || '').trim();
const messageBody = String(body.Body || body.body || '').trim();
const messageSid = String(body.MessageSid || body.SmsMessageSid || body.SmsSid || '').trim();
const waId = String(body.WaId || '').trim();
const profileName = String(body.ProfileName || '').trim();
const numMedia = parseInt(body.NumMedia || '0', 10) || 0;
const fromPhone = fromRaw.replace(/^whatsapp:/i, '').replace(/[\s\-().]/g, '');
if (!fromPhone || !/^\+?[1-9]\d{6,14}$/.test(fromPhone)) {
  return [{ json: { _skip: true, reason: 'Could not extract valid Twilio WhatsApp sender', rawFrom: fromRaw } }];
}
const normalizedPhone = fromPhone.startsWith('+') ? fromPhone : '+' + fromPhone;
if (!messageBody && numMedia === 0) {
  return [{ json: { _skip: true, reason: 'Blank Twilio inbound message', _from_phone: normalizedPhone, _message_sid: messageSid } }];
}
const lowerMsg = messageBody.toLowerCase();
let classification = 'responded';
const confirmedKeywords = ['yes', 'confirm', 'confirmed', 'will come', 'coming', 'ok', 'okay', 'sure', 'yep', 'yup', 'absolutely', 'definitely', "i'll be there", 'see you', 'good'];
const cancelledKeywords = ['no', 'cancel', 'cancelled', 'reschedule', "can't make it", 'cannot come', 'not coming', 'postpone', 'change date'];
const bookKeywords = ['book', 'schedule', 'appointment', 'want to book', 'fix appointment'];
if (lowerMsg === 'help' || ['not well','pain','emergency','urgent','need doctor','call me'].some(k => lowerMsg.includes(k))) classification = 'help';
else if (cancelledKeywords.some(k => lowerMsg.includes(k))) classification = 'cancelled';
else if (confirmedKeywords.some(k => lowerMsg.includes(k))) classification = 'confirmed';
else if (bookKeywords.some(k => lowerMsg.includes(k))) classification = 'book';
return [{ json: { _from_phone: normalizedPhone, _to_phone: toRaw, _message_body: messageBody, _classification: classification, _received_at: new Date().toISOString(), _message_sid: messageSid, _wa_id: waId, _profile_name: profileName, _num_media: numMedia } }];

const patientRows = $input.all();
const parsed = $('Parse and Classify Message').first().json;
const inboundPhone = parsed._from_phone;
const classification = parsed._classification;
const messageBody = parsed._message_body;
const receivedAt = parsed._received_at;

const matchedPatient = patientRows.length > 0 && patientRows[0].json.id ? patientRows[0].json : null;

if (!matchedPatient) {
  return [{
    json: {
      _found: false,
      _from_phone: inboundPhone,
      _classification: classification,
      _message_body: messageBody,
      _received_at: receivedAt,
      _log_message: `Unrecognised sender: ${inboundPhone}`
    }
  }];
}

const patientName = matchedPatient.name || 'there';
let autoReply = null;

if (classification === 'confirmed') {
  autoReply = `Thank you, ${patientName}! ✅ We've noted that you'll be coming in for your appointment. See you then!\n\nIf anything changes, feel free to message us.`;
} else if (classification === 'cancelled') {
  autoReply = `Hi ${patientName}, no problem at all! 😊 We've noted that you'd like to reschedule. A member of our team will reach out to you shortly to arrange a new time.\n\nThank you for letting us know!`;
} else if (classification === 'help') {
  autoReply = `Hi ${patientName}, we're sorry to hear that. 🙏 Please stay calm — we've flagged this for our team and someone will reach out to you very soon. If this is an emergency, please call your nearest hospital.`;
}

let responseStatusDb = 'responded';
if (classification === 'confirmed') responseStatusDb = 'confirmed';
else if (classification === 'cancelled') responseStatusDb = 'cancelled';

return [{
  json: {
    _found: true,
    _patient_id: matchedPatient.id,
    _patient_name: patientName,
    _from_phone: inboundPhone,
    _classification: classification,
    _message_body: messageBody,
    _received_at: receivedAt,
    _auto_reply: autoReply,
    _should_reply: autoReply !== null,
    _response_status_db: responseStatusDb
  }
}];
